// Budujemy zapytanie Overpass API dla POI w promieniu 5km
const geoData = $input.item.json;
const lat = parseFloat((geoData.lat || geoData[0]?.lat) || 52.2297);
const lon = parseFloat((geoData.lon || geoData[0]?.lon) || 21.0122);
const radius = 5000; // 5km

// Szukamy miejsc spacerowych: parki, fontanny, rzeźby, punkty widokowe, zamki
const query = `[out:json][timeout:25];
(
  node["leisure"="park"](around:${radius},${lat},${lon});
  node["amenity"="fountain"](around:${radius},${lat},${lon});
  node["tourism"="viewpoint"](around:${radius},${lat},${lon});
  node["tourism"="artwork"](around:${radius},${lat},${lon});
  node["historic"="castle"](around:${radius},${lat},${lon});
  node["historic"="monument"](around:${radius},${lat},${lon});
  node["tourism"="museum"](around:${radius},${lat},${lon});
  way["leisure"="park"](around:${radius},${lat},${lon});
  way["tourism"="attraction"](around:${radius},${lat},${lon});
);
out center body 40;`;

return [{ json: { query, centerLat: lat, centerLon: lon } }];

// ============================================
// PULA POI I WYBÓR PUNKTU STARTOWEGO
// ============================================
const overpassData = $('Overpass: Get POIs').item.json;
const webhookBody = $('Webhook').item.json.body;

const elements = overpassData.elements || [];
const allPOIs = [];

for (const el of elements) {
  const lat = el.lat || el.center?.lat;
  const lon = el.lon || el.center?.lon;
  const tags = el.tags || {};
  const name = tags.name || tags['name:pl'] || tags['name:en'];

  if (!lat || !lon || !name) continue;

  let priority = 1;
  if (tags.leisure === 'park') priority = 4;
  if (tags.amenity === 'fountain') priority = 4;
  if (tags.tourism === 'viewpoint') priority = 3;
  if (tags.tourism === 'artwork') priority = 3;
  if (tags.historic === 'castle') priority = 2;
  if (tags.historic === 'monument') priority = 2;
  if (tags.tourism === 'museum') priority = 0;

  const nameLower = name.toLowerCase();
  const sadWords = ['powstań', 'poległ', 'walcząca', 'lotnika', 'ofiar', 'męczenni', 'katyń', 'cmentarz'];
  if (tags.historic === 'monument' && sadWords.some(w => nameLower.includes(w))) priority = -1;

  const isDuplicate = allPOIs.some(p => p.name.toLowerCase() === nameLower);
  if (isDuplicate || priority === -1) continue;

  allPOIs.push({
    name, lat: parseFloat(lat), lon: parseFloat(lon),
    category: tags.leisure || tags.amenity || tags.historic || tags.tourism || 'atrakcja',
    priority
  });
}

allPOIs.sort((a, b) => b.priority - a.priority);
if (allPOIs.length < 3) return [{ json: { error: 'Za mało punktów' } }];

// Wybieramy losowy start z TOP 5
const startIndex = Math.floor(Math.random() * Math.min(5, allPOIs.length));
const startPOI = allPOIs.splice(startIndex, 1)[0];

return [{
  json: {
    startPOI: startPOI,
    availablePOIs: allPOIs.slice(0, 15), // Bierzemy max 15 najlepszych
    city: webhookBody.city,
    ageGroup: webhookBody.ageGroup,
    sessionId: webhookBody.sessionId
  }
}];

const webhookData = $('Webhook').item.json.body;
const airtableRecord = $('Airtable: Check Session').item.json;
const isNewSession = !airtableRecord.id;

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1 * Math.PI/180) * Math.cos(lat2 * Math.PI/180) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

let availablePOIs = [];
let visitedPOIs = [];
let inventory = [];
let questGoal = "";
let currentPOI = null;
let currentStepIndex = 0;
let totalSteps = 8;
let airtableId = airtableRecord.id;

if (isNewSession) {
  const initData = $('Select POI Pool').item.json;
  currentPOI = initData.startPOI;
  availablePOIs = initData.availablePOIs || [];
  visitedPOIs = [currentPOI];
  inventory = [];
  airtableId = $('Airtable: Create Session').item.json.id;
  questGoal = "GENERATE_NEW";
} else {
  const fields = airtableRecord.fields || {};
  try { availablePOIs = JSON.parse(fields.Available_POIs || '[]'); } catch(e) {}
  try { visitedPOIs = JSON.parse(fields.Visited_POIs || '[]'); } catch(e) {}
  try { inventory = JSON.parse(fields.Inventory || '[]'); } catch(e) {}
  questGoal = fields.Quest_Goal || "";
  currentStepIndex = parseInt(fields.Current_Step_Index || '0');
  totalSteps = parseInt(fields.Total_Steps || '8');

  const chosenTargetName = webhookData.userChoice;

  // Znajdz wybrany cel i zrob z niego currentPOI
  if (chosenTargetName && chosenTargetName !== 'Start') {
    const foundIdx = availablePOIs.findIndex(p => p.name === chosenTargetName);
    if (foundIdx >= 0) {
      currentPOI = availablePOIs.splice(foundIdx, 1)[0];
      visitedPOIs.push(currentPOI);
    } else {
      currentPOI = availablePOIs.length > 0 ? availablePOIs.shift() : visitedPOIs[visitedPOIs.length-1];
    }
  } else {
    currentPOI = visitedPOIs[visitedPOIs.length-1];
  }
}

// Znajdz 2 najblizsze z availablePOIs
if (currentPOI && availablePOIs.length > 0) {
  availablePOIs.sort((a,b) => haversine(currentPOI.lat, currentPOI.lon, a.lat, a.lon) - haversine(currentPOI.lat, currentPOI.lon, b.lat, b.lon));
}
const optionA = availablePOIs.length > 0 ? availablePOIs[0] : null;
const optionB = availablePOIs.length > 1 ? availablePOIs[1] : null;

const agePrompts = {
  "3-6": "Pisz prosto, jak do 4-latka. Radosny ton, magia.",
  "7-11": "Pisz jak do odkrywcy. Zagadki detektywistyczne, lekka fabuła.",
  "12+": "Pisz konkretnie, fakty historyczne w klimacie urban fantasy."
};

return [{
  json: {
    city: webhookData.city || "miasto",
    ageGroup: webhookData.ageGroup || "7-11",
    agePrompt: agePrompts[webhookData.ageGroup] || agePrompts["7-11"],
    currentPOI,
    optionA,
    optionB,
    availablePOIs,
    visitedPOIs,
    inventory,
    questGoal,
    currentStepIndex,
    totalSteps,
    airtableId,
    userChoice: webhookData.userChoice || "Start"
  }
}];

const ctx = $('Prepare Context').item.json;
const item = $input.item.json;
if (ctx.error) return [{ json: { error: ctx.error } }];

let parsed = {};
try {
  let rawText = '';
  if (typeof item.text === 'string') rawText = item.text;
  else if (item.content && item.content.parts) rawText = item.content.parts[0].text;
  else if (item.candidates) rawText = item.candidates[0].content.parts[0].text;

  if (rawText) {
    const cleanText = rawText.replace(/\s*```json\n?/gi, '').replace(/\s*```\n?/gi, '').trim();
    parsed = JSON.parse(cleanText);
  }
} catch(e) {
  parsed = { narrative_text: "Błąd AI. " + e.message, choices: [] };
}

parsed.city = ctx.city;
parsed.airtableId = ctx.airtableId;
parsed.currentStepIndex = ctx.currentStepIndex;
parsed.totalSteps = ctx.totalSteps;
parsed.currentPOI = ctx.currentPOI;

// Ekwipunek
let inventory = ctx.inventory || [];
if (parsed.item_found && parsed.item_found !== "null") {
  inventory.push(parsed.item_found);
}
parsed.inventory = inventory;
parsed.availablePOIs = ctx.availablePOIs || [];
parsed.visitedPOIs = ctx.visitedPOIs || [];
parsed.questGoal = parsed.quest_goal || ctx.questGoal;

return [{ json: parsed }];

